contracts/FarmerRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "@openzeppelin/contracts/access/AccessControl.sol";

contract FarmerRegistry is AccessControl {
    bytes32 public constant TESTER_ROLE = keccak256("TESTER_ROLE");
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");

    struct Farmer {
        uint256 farmerId;
        string farmerName;
        string farmLocation;
        string farmSize;
        string farmingType; // organic / non-organic
        string cropType;
        uint256 expectedYield;
        uint256 cultivationDate;
        address walletAddress;
        bool isRegistered;
        bool isApproved;
    }

    mapping(uint256 => Farmer) public farmers;
    uint256[] public farmerIds;

    event FarmerRegistered(
        uint256 indexed farmerId,
        string farmerName,
        address indexed walletAddress,
        string cropType
    );

    event FarmerApproved(uint256 indexed farmerId, address indexed verifier);
    event FarmerRejected(uint256 indexed farmerId, address indexed verifier);

    constructor() {
        _setupRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _setupRole(ADMIN_ROLE, msg.sender);
    }

    function registerFarmer(
        uint256 _farmerId,
        string memory _name,
        string memory _location,
        string memory _size,
        string memory _farmingType,
        string memory _cropType,
        uint256 _expectedYield,
        uint256 _cultivationDate
    ) public {
        require(!farmers[_farmerId].isRegistered, "Farmer ID already registered");

        farmers[_farmerId] = Farmer({
            farmerId: _farmerId,
            farmerName: _name,
            farmLocation: _location,
            farmSize: _size,
            farmingType: _farmingType,
            cropType: _cropType,
            expectedYield: _expectedYield,
            cultivationDate: _cultivationDate,
            walletAddress: msg.sender,
            isRegistered: true,
            isApproved: false
        });

        farmerIds.push(_farmerId);

        emit FarmerRegistered(_farmerId, _name, msg.sender, _cropType);
    }

    function approveFarmer(uint256 _farmerId) public {
        require(hasRole(TESTER_ROLE, msg.sender) || hasRole(ADMIN_ROLE, msg.sender), "Caller is not an authorized tester or admin");
        require(farmers[_farmerId].isRegistered, "Farmer not registered");
        require(!farmers[_farmerId].isApproved, "Farmer already approved");

        farmers[_farmerId].isApproved = true;

        emit FarmerApproved(_farmerId, msg.sender);
    }

    function rejectFarmer(uint256 _farmerId) public {
        require(hasRole(TESTER_ROLE, msg.sender) || hasRole(ADMIN_ROLE, msg.sender), "Caller is not an authorized tester or admin");
        require(farmers[_farmerId].isRegistered, "Farmer not registered");

        farmers[_farmerId].isRegistered = false;
        farmers[_farmerId].isApproved = false;

        emit FarmerRejected(_farmerId, msg.sender);
    }

    function getFarmer(uint256 _farmerId) public view returns (Farmer memory) {
        require(farmers[_farmerId].isRegistered, "Farmer not registered");
        return farmers[_farmerId];
    }

    function getFarmerCount() public view returns (uint256) {
        return farmerIds.length;
    }

    function isFarmerApproved(uint256 _farmerId) public view returns (bool) {
        return farmers[_farmerId].isApproved;
    }
}

contracts/MicroFinance.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "@openzeppelin/contracts/access/Ownable.sol";
import "./FarmerRegistry.sol";
import "./ProductRegistry.sol";

contract MicroFinance is Ownable {
    struct Investment {
        uint256 investmentId;
        address investor;
        uint256 farmerId;
        uint256 lotNumber;
        uint256 amount; // Amount funded in Wei
        uint256 timestamp;
        uint256 profitPercentage; // Profit margin set for investor
        string status; // "ACTIVE", "COMPLETED", "REFUNDED"
    }

    Investment[] public investments;
    mapping(uint256 => uint256[]) public farmerInvestments;
    mapping(address => uint256[]) public investorInvestments;

    FarmerRegistry public farmerRegistry;
    ProductRegistry public productRegistry;

    event InvestmentMade(
        uint256 indexed investmentId,
        address indexed investor,
        uint256 indexed farmerId,
        uint256 lotNumber,
        uint256 amount,
        uint256 timestamp
    );

    event InvestmentStatusUpdated(
        uint256 indexed investmentId,
        string status
    );

    constructor(address _farmerRegistryAddress, address _productRegistryAddress) {
        farmerRegistry = FarmerRegistry(_farmerRegistryAddress);
        productRegistry = ProductRegistry(_productRegistryAddress);
    }

    function invest(
        uint256 _farmerId,
        uint256 _lotNumber,
        uint256 _profitPercentage
    ) public payable {
        require(msg.value > 0, "Investment amount must be greater than zero");

        // Verify Farmer is approved
        require(farmerRegistry.isFarmerApproved(_farmerId), "Farmer must be approved by authority");

        // Verify Farmer wallet address
        address farmerWallet = farmerRegistry.getFarmer(_farmerId).walletAddress;
        require(farmerWallet != address(0), "Farmer wallet address not found");
        require(farmerWallet != msg.sender, "Farmers cannot invest in their own crops");

        // Verify product lot exists
        require(productRegistry.isProductExists(_lotNumber), "Product lot does not exist");

        uint256 newInvestmentId = investments.length;

        investments.push(Investment({
            investmentId: newInvestmentId,
            investor: msg.sender,
            farmerId: _farmerId,
            lotNumber: _lotNumber,
            amount: msg.value,
            timestamp: block.timestamp,
            profitPercentage: _profitPercentage,
            status: "ACTIVE"
        }));

        farmerInvestments[_farmerId].push(newInvestmentId);
        investorInvestments[msg.sender].push(newInvestmentId);

        // Forward the ETH directly to the farmer
        (bool success, ) = payable(farmerWallet).call{value: msg.value}("");
        require(success, "Failed to transfer funds to farmer");

        emit InvestmentMade(
            newInvestmentId,
            msg.sender,
            _farmerId,
            _lotNumber,
            msg.value,
            block.timestamp
        );
    }

    function updateInvestmentStatus(uint256 _investmentId, string memory _status) public {
        require(_investmentId < investments.length, "Invalid investment ID");

        // Only the farmer of this crop, or the contract owner can update status
        uint256 farmerId = investments[_investmentId].farmerId;
        address farmerWallet = farmerRegistry.getFarmer(farmerId).walletAddress;

        require(msg.sender == farmerWallet || msg.sender == owner(), "Only the farmer or owner can update status");

        investments[_investmentId].status = _status;

        emit InvestmentStatusUpdated(_investmentId, _status);
    }

    // Custom getter to return a full Investment struct to bypass tuple restrictions
    function getInvestment(uint256 _investmentId) public view returns (Investment memory) {
        require(_investmentId < investments.length, "Invalid investment ID");
        return investments[_investmentId];
    }

    function getInvestmentCount() public view returns (uint256) {
        return investments.length;
    }

    function getFarmerInvestments(uint256 _farmerId) public view returns (uint256[] memory) {
        return farmerInvestments[_farmerId];
    }

    // Helper to check if an address has investments
    function getInvestorInvestments(address _investor) public view returns (uint256[] memory) {
        return investorInvestments[_investor];
    }
}

contracts/ProductRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "./FarmerRegistry.sol";

contract ProductRegistry is AccessControl {
    bytes32 public constant TESTER_ROLE = keccak256("TESTER_ROLE");
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");

    struct Product {
        uint256 lotNumber;
        uint256 farmerId;
        string cropName;
        string qualityGrade;
        uint256 price; // Price per unit or total price in Wei
        uint256 testDate;
        uint256 expiryDate;
        string certificationStatus;
        address testerAddress;
        bool exists;
    }

    mapping(uint256 => Product) public products;
    uint256[] public lotNumbers;

    FarmerRegistry public farmerRegistry;

    event ProductRegistered(
        uint256 indexed lotNumber,
        uint256 indexed farmerId,
        string cropName,
        string qualityGrade,
        uint256 price,
        address indexed tester
    );

    constructor(address _farmerRegistryAddress) {
        _setupRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _setupRole(ADMIN_ROLE, msg.sender);
        farmerRegistry = FarmerRegistry(_farmerRegistryAddress);
    }

    function registerProduct(
        uint256 _lotNumber,
        uint256 _farmerId,
        string memory _cropName,
        string memory _qualityGrade,
        uint256 _price,
        uint256 _testDate,
        uint256 _expiryDate,
        string memory _certificationStatus
    ) public {
        require(hasRole(TESTER_ROLE, msg.sender) || hasRole(ADMIN_ROLE, msg.sender), "Caller is not an authorized tester or admin");
        require(!products[_lotNumber].exists, "Lot number already registered");
        require(farmerRegistry.isFarmerApproved(_farmerId), "Farmer is not approved by Quality Authority");

        products[_lotNumber] = Product({
            lotNumber: _lotNumber,
            farmerId: _farmerId,
            cropName: _cropName,
            qualityGrade: _qualityGrade,
            price: _price,
            testDate: _testDate,
            expiryDate: _expiryDate,
            certificationStatus: _certificationStatus,
            testerAddress: msg.sender,
            exists: true
        });

        lotNumbers.push(_lotNumber);

        emit ProductRegistered(
            _lotNumber,
            _farmerId,
            _cropName,
            _qualityGrade,
            _price,
            msg.sender
        );
    }

    function getProduct(uint256 _lotNumber) public view returns (Product memory) {
        require(products[_lotNumber].exists, "Product lot does not exist");
        return products[_lotNumber];
    }

    function isProductExists(uint256 _lotNumber) public view returns (bool) {
        return products[_lotNumber].exists;
    }

    function getProductCount() public view returns (uint256) {
        return lotNumbers.length;
    }
}

contracts/RatingSystem.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "./FarmerRegistry.sol";

contract RatingSystem {
    struct Rating {
        uint256 ratingId;
        address consumer;
        uint256 farmerId;
        uint256 lotNumber;
        uint8 reliability; // 1 to 5
        uint8 productQuality; // 1 to 5
        uint8 deliverySatisfaction; // 1 to 5
        string comment;
        uint256 timestamp;
    }

    Rating[] public ratings;
    mapping(uint256 => uint256[]) public farmerRatings;

    FarmerRegistry public farmerRegistry;

    event RatingAdded(
        uint256 indexed ratingId,
        address indexed consumer,
        uint256 indexed farmerId,
        uint256 lotNumber,
        uint8 reliability,
        uint8 productQuality,
        uint8 deliverySatisfaction,
        uint256 timestamp
    );

    constructor(address _farmerRegistryAddress) {
        farmerRegistry = FarmerRegistry(_farmerRegistryAddress);
    }

    function addRating(
        uint256 _farmerId,
        uint256 _lotNumber,
        uint8 _reliability,
        uint8 _productQuality,
        uint8 _deliverySatisfaction,
        string memory _comment
    ) public {
        require(farmerRegistry.isFarmerApproved(_farmerId), "Farmer must be approved by authority");
        require(
            _reliability >= 1 && _reliability <= 5 &&
            _productQuality >= 1 && _productQuality <= 5 &&
            _deliverySatisfaction >= 1 && _deliverySatisfaction <= 5,
            "Ratings must be between 1 and 5"
        );

        uint256 newRatingId = ratings.length;

        ratings.push(Rating({
            ratingId: newRatingId,
            consumer: msg.sender,
            farmerId: _farmerId,
            lotNumber: _lotNumber,
            reliability: _reliability,
            productQuality: _productQuality,
            deliverySatisfaction: _deliverySatisfaction,
            comment: _comment,
            timestamp: block.timestamp
        }));

        farmerRatings[_farmerId].push(newRatingId);

        emit RatingAdded(
            newRatingId,
            msg.sender,
            _farmerId,
            _lotNumber,
            _reliability,
            _productQuality,
            _deliverySatisfaction,
            block.timestamp
        );
    }

    function getFarmerRatingCount(uint256 _farmerId) public view returns (uint256) {
        return farmerRatings[_farmerId].length;
    }

    function getFarmerAverageRating(uint256 _farmerId) public view returns (uint256) {
        uint256 count = farmerRatings[_farmerId].length;
        if (count == 0) return 0;

        uint256 total = 0;
        for (uint256 i = 0; i < count; i++) {
            uint256 rId = farmerRatings[_farmerId][i];
            total += (ratings[rId].reliability + ratings[rId].productQuality + ratings[rId].deliverySatisfaction) / 3;
        }

        // Return average scaled by 10 (e.g. 45 represents 4.5) to keep precision
        return (total * 10) / count;
    }
}

